#include <stdio.h>
#include <stdlib.h>

// Function to calculate the colorfulness of a permutation
int calculateColorfulness(int* permutation, int* colors, int n, int k) {
    int colorfulness = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + k; j < n; j++) {
            if (colors[permutation[i]] == colors[permutation[j]]) {
                colorfulness++;
            }
        }
    }
    return colorfulness;
}

// Function to generate all permutations of the blocks
void generatePermutations(int* permutation, int* colors, int n, int k, int index, int* totalColorfulness) {
    if (index == n) {
        int colorfulness = calculateColorfulness(permutation, colors, n, k);
        *totalColorfulness += colorfulness;
    } else {
        for (int i = 0; i < n; i++) {
            int found = 0;
            for (int j = 0; j < index; j++) {
                if (permutation[j] == i) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                permutation[index] = i;
                generatePermutations(permutation, colors, n, k, index + 1, totalColorfulness);
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n, k;
        scanf("%d %d", &n, &k);
        int* colors = (int*)malloc(n * sizeof(int));
        int* sizes = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &sizes[i], &colors[i]);
        }
        int* permutation = (int*)malloc(n * sizeof(int));
        int totalColorfulness = 0;
        generatePermutations(permutation, colors, n, k, 0, &totalColorfulness);
        double expectedColorfulness = (double)totalColorfulness / factorial(n);
        printf("%.10f\n", expectedColorfulness);
        free(permutation);
        free(colors);
        free(sizes);
    }
    return 0;
}

// Function to calculate the factorial of a number
int factorial(int n) {
    int result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

