import math
import itertools

def calculate_colorfulness(permutation, colors, n, k):
    colorfulness = 0
    for i in range(n):
        for j in range(i + k, n):
            if colors[permutation[i]] == colors[permutation[j]]:
                colorfulness += 1
    return colorfulness

def generate_permutations(colors, n, k, sizes):
    total_colorfulness = 0
    for permutation in itertools.permutations(range(n)):
        colorfulness = calculate_colorfulness(permutation, colors, n, k)
        total_colorfulness += colorfulness
    expected_colorfulness = total_colorfulness / math.factorial(n)
    return expected_colorfulness

def main():
    T = int(input())
    for _ in range(T):
        n, k = map(int, input().split())
        colors = []
        sizes = []
        for _ in range(n):
            size, color = map(int, input().split())
            sizes.append(size)
            colors.append(color)
        expected_colorfulness = generate_permutations(colors, n, k, sizes)
        print(f"{expected_colorfulness:.10f}")

if __name__ == '__main__':
    main()

