function getPermutations(n) {
    let permutations = [];
    let arr = Array.from({ length: n }, (_, i) => i);
    permute(arr, 0, n - 1, permutations);
    return permutations;
}

function permute(arr, l, r, permutations) {
    if (l === r) {
        permutations.push([...arr]);
    } else {
        for (let i = l; i <= r; i++) {
            [arr[l], arr[i]] = [arr[i], arr[l]];
            permute(arr, l + 1, r, permutations);
            [arr[l], arr[i]] = [arr[i], arr[l]];
        }
    }
}

function factorial(n) {
    let result = 1;
    for (let i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

